package com.hdarby.dicemaster.data.repository

import com.hdarby.dicemaster.data.local.dao.WeaponDao
import com.hdarby.dicemaster.data.local.entity.CharacterWeaponCrossRef
import com.hdarby.dicemaster.domain.model.Weapon
import io.mockk.coEvery
import io.mockk.coVerify
import io.mockk.every
import io.mockk.mockk
import kotlinx.coroutines.flow.flow
import kotlinx.coroutines.test.runTest
import org.junit.Assert.assertEquals
import org.junit.Test

class WeaponRepositoryErrorHandlingTest {

    private val weaponDao: WeaponDao = mockk()
    private val repository = WeaponRepositoryImpl(weaponDao)

    private val weapon = Weapon(
        id = 1,
        name = "Longsword",
        type = "Melee",
        damageDice = "1d8",
        damageType = "Slashing",
        modifier = 2
    )

    @Test
    fun `getWeapons handles database error`() = runTest {
        val errorMessage = "Database connection lost"
        every { weaponDao.getAllWeapons() } returns flow {
            throw Exception(errorMessage)
        }

        try {
            repository.getWeapons().collect { }
        } catch (e: Exception) {
            assertEquals(errorMessage, e.message)
        }
    }

    @Test
    fun `addWeapon handles constraint violation on duplicate name`() = runTest {
        val errorMessage = "UNIQUE constraint failed: weapon.name"
        coEvery { weaponDao.insertWeapon(any()) } throws Exception(errorMessage)

        try {
            repository.addWeapon(weapon)
        } catch (e: Exception) {
            assertEquals(errorMessage, e.message)
        }

        coVerify { weaponDao.insertWeapon(any()) }
    }

    @Test
    fun `updateWeapon with zero ID`() = runTest {
        val invalidWeapon = weapon.copy(id = 0)

        try {
            repository.updateWeapon(invalidWeapon)
        } catch (e: Exception) {
            assertEquals("Weapon ID must be valid", e.message)
        }
    }

    @Test
    fun `deleteWeapon removes weapon successfully`() = runTest {
        coEvery { weaponDao.deleteWeapon(any()) } returns Unit

        repository.deleteWeapon(weapon)

        coVerify { weaponDao.deleteWeapon(any()) }
    }

    @Test
    fun `assignWeaponToCharacter with foreign key constraint`() = runTest {
        val errorMessage = "FOREIGN KEY constraint failed"
        coEvery { weaponDao.insertCharacterWeaponCrossRef(any()) } throws Exception(errorMessage)

        try {
            repository.assignWeaponToCharacter(999L, 999L)
        } catch (e: Exception) {
            assertEquals(errorMessage, e.message)
        }
    }

    @Test
    fun `assignWeaponToCharacter creates cross reference`() = runTest {
        coEvery { weaponDao.insertCharacterWeaponCrossRef(any()) } returns Unit

        repository.assignWeaponToCharacter(1L, 1L)

        coVerify { weaponDao.insertCharacterWeaponCrossRef(any()) }
    }

    @Test
    fun `unassignWeaponFromCharacter removes cross reference`() = runTest {
        coEvery { weaponDao.deleteCharacterWeaponCrossRef(any()) } returns Unit

        repository.unassignWeaponFromCharacter(1L, 1L)

        coVerify { weaponDao.deleteCharacterWeaponCrossRef(any()) }
    }

    @Test
    fun `getWeapons with empty database returns empty flow`() = runTest {
        every { weaponDao.getAllWeapons() } returns flow {
            emit(emptyList())
        }

        val result = mutableListOf<Any>()
        repository.getWeapons().collect { result.add(it) }

        assertEquals(1, result.size)
        assertEquals(emptyList<Any>(), result[0])
    }

    @Test
    fun `addWeapon with high modifier value`() = runTest {
        val extremeWeapon = weapon.copy(modifier = 999)
        coEvery { weaponDao.insertWeapon(any()) } returns 1L

        val weaponId = repository.addWeapon(extremeWeapon)

        coVerify { weaponDao.insertWeapon(any()) }
        assertEquals(1L, weaponId)
    }

    @Test
    fun `updateWeapon handles negative modifier`() = runTest {
        val negativeModWeapon = weapon.copy(modifier = -5)
        coEvery { weaponDao.updateWeapon(any()) } returns Unit

        repository.updateWeapon(negativeModWeapon)

        coVerify { weaponDao.updateWeapon(any()) }
    }
}

