package com.hdarby.dicemaster.domain.usecase

import com.hdarby.dicemaster.domain.repository.DiceRepository
import io.mockk.every
import io.mockk.mockk
import io.mockk.verify
import org.junit.Assert.assertEquals
import org.junit.Test

class RollDiceUseCaseTest {

    private val repository: DiceRepository = mockk()
    private val useCase = RollDiceUseCase(repository)

    @Test
    fun `invoke should return sorted results and total from repository`() {
        // Given
        val unsortedResults = listOf(5, 20, 10)
        val expectedSortedResults = listOf(20, 10, 5)
        every { repository.rollDice(20, 3) } returns unsortedResults

        // When
        val result = useCase(20, 3)

        // Then
        assertEquals(expectedSortedResults, result.rolls)
        assertEquals(35, result.total)
        verify { repository.rollDice(20, 3) }
    }

    @Test
    fun `invoke should apply modifier to total`() {
        // Given
        val unsortedResults = listOf(5, 20, 10)
        every { repository.rollDice(20, 3) } returns unsortedResults

        // When
        val result = useCase(20, 3, modifier = 5)

        // Then
        assertEquals(40, result.total)
        assertEquals(5, result.modifier)
    }

    @Test
    fun `invoke should handle single result`() {
        // Given
        val unsortedResults = listOf(7)
        every { repository.rollDice(10, 1) } returns unsortedResults

        // When
        val result = useCase(10, 1)

        // Then
        assertEquals(unsortedResults, result.rolls)
        assertEquals(7, result.total)
        verify { repository.rollDice(10, 1) }
    }
}

package com.hdarby.dicemaster.domain.usecase

import com.hdarby.dicemaster.domain.repository.DiceRepository
import io.mockk.every
import io.mockk.mockk
import io.mockk.verify
import org.junit.Assert.assertEquals
import org.junit.Assert.assertTrue
import org.junit.Test

class RollDiceUseCaseTest {

    private val repository: DiceRepository = mockk()
    private val useCase = RollDiceUseCase(repository)

    @Test
    fun `invoke should return sorted results and total from repository`() {
        val unsortedResults = listOf(5, 20, 10)
        val expectedSortedResults = listOf(20, 10, 5)
        every { repository.rollDice(20, 3) } returns unsortedResults

        val result = useCase(20, 3)

        assertEquals(expectedSortedResults, result.rolls)
        assertEquals(35, result.total)
        verify { repository.rollDice(20, 3) }
    }

    @Test
    fun `invoke should apply positive modifier to total`() {
        val rolls = listOf(5, 20, 10)
        every { repository.rollDice(20, 3) } returns rolls

        val result = useCase(20, 3, modifier = 5)

        assertEquals(40, result.total)
        assertEquals(5, result.modifier)
    }

    @Test
    fun `invoke should apply negative modifier to total`() {
        val rolls = listOf(10, 8)
        every { repository.rollDice(6, 2) } returns rolls

        val result = useCase(6, 2, modifier = -3)

        assertEquals(15, result.total)
        assertEquals(-3, result.modifier)
    }

    @Test
    fun `invoke with zero modifier does not change total`() {
        val rolls = listOf(7)
        every { repository.rollDice(10, 1) } returns rolls

        val result = useCase(10, 1, modifier = 0)

        assertEquals(7, result.total)
        assertEquals(0, result.modifier)
    }

    @Test
    fun `invoke should handle single result`() {
        val rolls = listOf(7)
        every { repository.rollDice(10, 1) } returns rolls

        val result = useCase(10, 1)

        assertEquals(rolls, result.rolls)
        assertEquals(7, result.total)
        verify { repository.rollDice(10, 1) }
    }

    @Test
    fun `invoke sorts results in descending order`() {
        val unsorted = listOf(2, 5, 1, 4, 3)
        every { repository.rollDice(6, 5) } returns unsorted

        val result = useCase(6, 5)

        assertEquals(listOf(5, 4, 3, 2, 1), result.rolls)
    }

    @Test
    fun `invoke preserves duplicate values in sorted order`() {
        val rolls = listOf(3, 3, 5, 5, 1)
        every { repository.rollDice(6, 5) } returns rolls

        val result = useCase(6, 5)

        assertTrue(result.rolls[0] >= result.rolls[1])
        assertTrue(result.rolls[1] >= result.rolls[2])
        assertTrue(result.rolls[2] >= result.rolls[3])
        assertTrue(result.rolls[3] >= result.rolls[4])
    }

    @Test
    fun `invoke with modifier negative enough to produce negative total`() {
        val rolls = listOf(1)
        every { repository.rollDice(4, 1) } returns rolls

        val result = useCase(4, 1, modifier = -5)

        assertEquals(-4, result.total)
    }

    @Test
    fun `total equals sum of rolls plus modifier`() {
        val rolls = listOf(6, 4, 3)
        every { repository.rollDice(6, 3) } returns rolls

        val result = useCase(6, 3, modifier = 2)

        assertEquals(rolls.sum() + 2, result.total)
    }
}

package com.hdarby.dicemaster.viewmodel

import app.cash.turbine.test
import kotlinx.coroutines.test.runTest
import org.junit.Assert.assertEquals
import org.junit.Assert.assertTrue
import org.junit.Before
import org.junit.Test

class DebugViewModelTest {

    private lateinit var viewModel: DebugViewModel

    @Before
    fun setUp() {
        viewModel = DebugViewModel()
    }

    @Test
    fun `initial state contains stats for all expected die types`() = runTest {
        viewModel.uiState.test {
            val state = awaitItem()
            val faces = state.dieStatsList.map { it.faces }
            assertEquals(listOf(3, 4, 6, 8, 10, 12, 20, 100), faces)
            cancelAndIgnoreRemainingEvents()
        }
    }

    @Test
    fun `each die stats has totalRolls equal to faces times 1000`() = runTest {
        viewModel.uiState.test {
            val state = awaitItem()
            state.dieStatsList.forEach { stats ->
                assertEquals(
                    "Expected totalRolls = ${stats.faces * 1000} for d${stats.faces}",
                    stats.faces * 1000,
                    stats.totalRolls
                )
            }
            cancelAndIgnoreRemainingEvents()
        }
    }

    @Test
    fun `each die stats has frequencies only within valid range`() = runTest {
        viewModel.uiState.test {
            val state = awaitItem()
            state.dieStatsList.forEach { stats ->
                stats.frequencies.keys.forEach { face ->
                    assertTrue(
                        "Face value $face out of range for d${stats.faces}",
                        face in 1..stats.faces
                    )
                }
            }
            cancelAndIgnoreRemainingEvents()
        }
    }

    @Test
    fun `each die stats min and max are within valid range`() = runTest {
        viewModel.uiState.test {
            val state = awaitItem()
            state.dieStatsList.forEach { stats ->
                assertTrue("Min ${stats.min} < 1 for d${stats.faces}", stats.min >= 1)
                assertTrue("Max ${stats.max} > ${stats.faces} for d${stats.faces}", stats.max <= stats.faces)
            }
            cancelAndIgnoreRemainingEvents()
        }
    }

    @Test
    fun `each die stats mean is within expected range`() = runTest {
        viewModel.uiState.test {
            val state = awaitItem()
            state.dieStatsList.forEach { stats ->
                val expectedMidpoint = (stats.faces + 1) / 2.0
                val tolerance = stats.faces * 0.1
                assertTrue(
                    "Mean ${stats.mean} too far from expected midpoint $expectedMidpoint for d${stats.faces}",
                    stats.mean in (expectedMidpoint - tolerance)..(expectedMidpoint + tolerance)
                )
            }
            cancelAndIgnoreRemainingEvents()
        }
    }

    @Test
    fun `runSimulations refreshes the stats list`() = runTest {
        viewModel.uiState.test {
            val firstState = awaitItem()
            viewModel.runSimulations()
            val secondState = awaitItem()
            assertEquals(firstState.dieStatsList.size, secondState.dieStatsList.size)
            cancelAndIgnoreRemainingEvents()
        }
    }
}

package com.hdarby.dicemaster.viewmodel

import app.cash.turbine.test
import kotlin.math.sqrt
import kotlinx.coroutines.test.runTest
import org.junit.Assert.assertEquals
import org.junit.Assert.assertNotNull
import org.junit.Assert.assertTrue
import org.junit.Before
import org.junit.Test

class DebugViewModelTest {

    private lateinit var viewModel: DebugViewModel

    @Before
    fun setUp() {
        viewModel = DebugViewModel()
    }

    @Test
    fun `initial state contains stats for all expected die types`() = runTest {
        viewModel.uiState.test {
            val state = awaitItem()
            val faces = state.dieStatsList.map { it.faces }
            assertEquals(listOf(3, 4, 6, 8, 10, 12, 20, 100), faces)
            cancelAndIgnoreRemainingEvents()
        }
    }

    @Test
    fun `each die stats has totalRolls equal to faces times 1000`() = runTest {
        viewModel.uiState.test {
            val state = awaitItem()
            state.dieStatsList.forEach { stats ->
                assertEquals(
                    "Expected totalRolls = ${stats.faces * 1000} for d${stats.faces}",
                    stats.faces * 1000,
                    stats.totalRolls
                )
            }
            cancelAndIgnoreRemainingEvents()
        }
    }

    @Test
    fun `each die stats has frequencies only within valid range`() = runTest {
        viewModel.uiState.test {
            val state = awaitItem()
            state.dieStatsList.forEach { stats ->
                stats.frequencies.keys.forEach { face ->
                    assertTrue(
                        "Face value $face out of range for d${stats.faces}",
                        face in 1..stats.faces
                    )
                }
            }
            cancelAndIgnoreRemainingEvents()
        }
    }

    @Test
    fun `each die stats min and max are within valid range`() = runTest {
        viewModel.uiState.test {
            val state = awaitItem()
            state.dieStatsList.forEach { stats ->
                assertTrue("Min ${stats.min} < 1 for d${stats.faces}", stats.min >= 1)
                assertTrue("Max ${stats.max} > ${stats.faces} for d${stats.faces}", stats.max <= stats.faces)
            }
            cancelAndIgnoreRemainingEvents()
        }
    }

    @Test
    fun `each die stats mean is within expected range`() = runTest {
        viewModel.uiState.test {
            val state = awaitItem()
            state.dieStatsList.forEach { stats ->
                val expectedMidpoint = (stats.faces + 1) / 2.0
                val tolerance = stats.faces * 0.1
                assertTrue(
                    "Mean ${stats.mean} too far from expected midpoint $expectedMidpoint for d${stats.faces}",
                    stats.mean in (expectedMidpoint - tolerance)..(expectedMidpoint + tolerance)
                )
            }
            cancelAndIgnoreRemainingEvents()
        }
    }

    @Test
    fun `runSimulations refreshes the stats list`() = runTest {
        viewModel.uiState.test {
            val firstState = awaitItem()
            viewModel.runSimulations()
            val secondState = awaitItem()
            assertEquals(firstState.dieStatsList.size, secondState.dieStatsList.size)
            cancelAndIgnoreRemainingEvents()
        }
    }

    @Test
    fun `each die stats has positive stdDev`() = runTest {
        viewModel.uiState.test {
            val state = awaitItem()
            state.dieStatsList.forEach { stats ->
                assertTrue(
                    "Expected stdDev > 0 for d${stats.faces}, was ${stats.stdDev}",
                    stats.stdDev > 0.0
                )
            }
            cancelAndIgnoreRemainingEvents()
        }
    }

    @Test
    fun `each die stats stdDev is within expected statistical range`() = runTest {
        viewModel.uiState.test {
            val state = awaitItem()
            state.dieStatsList.forEach { stats ->
                // Theoretical std dev of a uniform distribution: sqrt((n^2 - 1) / 12)
                val theoreticalStdDev = sqrt((stats.faces.toLong() * stats.faces - 1) / 12.0)
                val tolerance = theoreticalStdDev * 0.15 // allow 15% tolerance
                assertTrue(
                    "StdDev ${stats.stdDev} too far from theoretical $theoreticalStdDev for d${stats.faces}",
                    stats.stdDev in (theoreticalStdDev - tolerance)..(theoreticalStdDev + tolerance)
                )
            }
            cancelAndIgnoreRemainingEvents()
        }
    }

    @Test
    fun `each die stats has non-null frequencies map`() = runTest {
        viewModel.uiState.test {
            val state = awaitItem()
            state.dieStatsList.forEach { stats ->
                assertNotNull("Frequencies should not be null for d${stats.faces}", stats.frequencies)
                assertTrue("Frequencies should not be empty for d${stats.faces}", stats.frequencies.isNotEmpty())
            }
            cancelAndIgnoreRemainingEvents()
        }
    }

    @Test
    fun `each die stats total frequencies sum equals totalRolls`() = runTest {
        viewModel.uiState.test {
            val state = awaitItem()
            state.dieStatsList.forEach { stats ->
                val frequencySum = stats.frequencies.values.sum()
                assertEquals(
                    "Frequency sum should equal totalRolls for d${stats.faces}",
                    stats.totalRolls,
                    frequencySum
                )
            }
            cancelAndIgnoreRemainingEvents()
        }
    }
}

package com.hdarby.dicemaster.viewmodel

import app.cash.turbine.test
import com.hdarby.dicemaster.domain.model.RollResult
import com.hdarby.dicemaster.domain.usecase.RollDiceUseCase
import io.mockk.coEvery
import io.mockk.every
import io.mockk.mockk
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.ExperimentalCoroutinesApi
import kotlinx.coroutines.test.UnconfinedTestDispatcher
import kotlinx.coroutines.test.resetMain
import kotlinx.coroutines.test.runTest
import kotlinx.coroutines.test.setMain
import org.junit.After
import org.junit.Assert.assertEquals
import org.junit.Before
import org.junit.Test

@OptIn(ExperimentalCoroutinesApi::class)
class DiceViewModelErrorHandlingTest {

    private val rollDiceUseCase: RollDiceUseCase = mockk()
    private val testDispatcher = UnconfinedTestDispatcher()

    @Before
    fun setup() {
        Dispatchers.setMain(testDispatcher)
    }

    @After
    fun tearDown() {
        Dispatchers.resetMain()
    }

    @Test
    fun `rollDice handles exception gracefully`() = runTest {
        val errorMessage = "Random number generation failed"
        coEvery { rollDiceUseCase(any(), any(), any()) } throws Exception(errorMessage)

        val viewModel = DiceViewModel(rollDiceUseCase)
        viewModel.updateQuantity(3)
        viewModel.updateFaces(6)

        viewModel.rollDice()

        viewModel.uiState.test {
            val state = awaitItem()
            assertEquals(errorMessage, state.error)
        }
    }

    @Test
    fun `updateModifier with negative value`() = runTest {
        coEvery { rollDiceUseCase(any(), any(), any()) } returns RollResult(
            rolls = listOf(5, 4, 3),
            faces = 6,
            modifier = -5
        )

        val viewModel = DiceViewModel(rollDiceUseCase)

        viewModel.updateQuantity(3)
        viewModel.updateFaces(6)
        viewModel.updateModifier(-5)

        viewModel.uiState.test {
            val state = awaitItem()
            assertEquals(-5, state.modifier)
            assertEquals(null, state.error)
        }
    }

    @Test
    fun `updateModifier persists zero value`() = runTest {
        val viewModel = DiceViewModel(rollDiceUseCase)

        viewModel.updateModifier(0)

        viewModel.uiState.test {
            val state = awaitItem()
            assertEquals(0, state.modifier)
        }
    }

    @Test
    fun `rollDice with different configurations`() = runTest {
        val roll1 = RollResult(rolls = listOf(20), faces = 20, modifier = 0)
        val roll2 = RollResult(rolls = listOf(1, 1), faces = 4, modifier = 2)

        coEvery { rollDiceUseCase(20, 1, 0) } returns roll1
        coEvery { rollDiceUseCase(4, 2, 2) } returns roll2

        val viewModel = DiceViewModel(rollDiceUseCase)

        viewModel.updateFaces(20)
        viewModel.updateQuantity(1)
        viewModel.updateModifier(0)
        viewModel.rollDice()

        viewModel.updateFaces(4)
        viewModel.updateQuantity(2)
        viewModel.updateModifier(2)
        viewModel.rollDice()

        viewModel.uiState.test {
            val state = awaitItem()
            assertEquals(roll2, state.rollResult)
        }
    }

    @Test
    fun `dismissResults hides results`() = runTest {
        coEvery { rollDiceUseCase(any(), any(), any()) } returns RollResult(
            rolls = listOf(5),
            faces = 6,
            modifier = 0
        )

        val viewModel = DiceViewModel(rollDiceUseCase)

        viewModel.rollDice()
        viewModel.dismissResults()

        viewModel.uiState.test {
            val state = awaitItem()
            assertEquals(false, state.showResults)
        }
    }
}

